        if (remove) {
            msg.payload[0].labels.splice(x, 1);
            for (d = 0; d < msg.payload[0].data.length; d++) {
                 msg.payload[0].data[d].splice(x, 1);
            }
            x--;
        }
        x++;
    }
    // Still the first and last datapoints should be zero, so
