}
else if (msg.topic === 'hourly-day-nav') {
    const action = msg.payload && msg.payload.action;

    if (action === 'prev') {
        selectedDate = shiftDay(selectedDate, -1);
    }
    else if (action === 'next') {
        selectedDate = shiftDay(selectedDate, 1);
        if (selectedDate > todayKey) {
            selectedDate = todayKey;
        }
    }
    else {
        selectedDate = todayKey;
    }
}

